namespace BlazorNotifications.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly string[] _templates =
    [
        "Your build completed successfully.",
        "New comment on pull request #42.",
        "Deployment to production finished.",
        "CI pipeline failed for branch 'feature/login'.",
        "You were mentioned in issue #108.",
        "Security alert: dependency update available.",
        "Code review requested by @alice.",
        "Release v2.1.0 published.",
    ];

    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        lock (_lock)
        {
            var notifications = new List<Notification>();
            for (var i = 0; i < 3; i++)
            {
                notifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = _templates[i % _templates.Length],
                    Timestamp = DateTime.UtcNow.AddMinutes(-10 + i)
                });
            }
            return Task.FromResult(notifications);
        }
    }

    public Task<List<Notification>> CheckForNewNotificationsAsync()
    {
        lock (_lock)
        {
            // Simulate: ~50 % chance a new notification arrives each poll
            if (Random.Shared.NextDouble() < 0.5)
            {
                return Task.FromResult(new List<Notification>());
            }

            var n = new Notification
            {
                Id = _nextId++,
                Message = _templates[Random.Shared.Next(_templates.Length)],
                Timestamp = DateTime.UtcNow
            };

            return Task.FromResult(new List<Notification> { n });
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject BlazorNotifications.Services.NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<BlazorNotifications.Services.Notification>? notifications { get; set; }

    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        // Only fetch if not already restored from prerender state
        notifications ??= await NotificationService.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Start polling only after the component is interactive (never during prerender)
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                var newItems = await NotificationService.CheckForNewNotificationsAsync();
                if (newItems.Count > 0)
                {
                    notifications ??= [];
                    notifications.InsertRange(0, newItems);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

